import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine().trim(); // Read the entire line and trim any leading/trailing spaces

        int maxLength = 10; // Maximum allowed length for the buffer
        char[] buffer = new char[maxLength];

        if (input.length() > maxLength) {
            System.out.println("Input exceeds maximum allowed length. Aborting.");
            return;
        }

        // Copy the user input into the buffer with proper bounds checking
        for (int i = 0; i < input.length(); i++) {
            if (i < maxLength) {
                buffer[i] = input.charAt(i);
            } else {
                break; // Stop copying if we reach the end of the buffer
            }
        }

        System.out.println("Buffer overflow vulnerability fixed!");
    }
}

